#include "controller.h"

static void controller_set_state(controller_t *controller, controller_state_t state, bool filter_on, bool drain_open)
{
    if (controller == 0) {
        return;
    }

    controller->state = state;
    controller->filter_on = filter_on;
    controller->drain_open = drain_open;
}

static void controller_set_safe_idle(controller_t *controller)
{
    controller_set_state(controller, CONTROLLER_STATE_SAFE_IDLE, false, false);
}

static void controller_set_filtering(controller_t *controller)
{
    controller_set_state(controller, CONTROLLER_STATE_FILTERING, true, false);
}

static void controller_set_settling(controller_t *controller, uint32_t now_ms)
{
    if (controller == 0) {
        return;
    }

    controller_set_state(controller, CONTROLLER_STATE_SETTLING, false, false);
    controller->settling_started_ms = now_ms;
}

static void controller_set_draining(controller_t *controller)
{
    controller_set_state(controller, CONTROLLER_STATE_DRAINING, false, true);
}

static void controller_set_complete(controller_t *controller)
{
    controller_set_state(controller, CONTROLLER_STATE_COMPLETE, false, false);
}

static bool controller_elapsed_more_than(uint32_t now_ms, uint32_t start_ms, uint32_t limit_ms)
{
    return (uint32_t) (now_ms - start_ms) > limit_ms;
}

static bool controller_elapsed_at_least(uint32_t now_ms, uint32_t start_ms, uint32_t limit_ms)
{
    return (uint32_t) (now_ms - start_ms) >= limit_ms;
}

static bool controller_turbidity_fresh(const controller_t *controller, uint32_t now_ms)
{
    return (controller != 0) &&
           controller->has_valid_turbidity &&
           !controller_elapsed_more_than(now_ms, controller->last_turbidity_ms, CONTROLLER_SENSOR_TIMEOUT_MS);
}

static bool controller_level_fresh(const controller_t *controller, uint32_t now_ms)
{
    return (controller != 0) &&
           controller->has_valid_level &&
           !controller_elapsed_more_than(now_ms, controller->last_level_ms, CONTROLLER_SENSOR_TIMEOUT_MS);
}

static void controller_clamp_clear_streak(controller_t *controller)
{
    if ((controller != 0) && (controller->clear_streak_count > CONTROLLER_CLEAR_STREAK_REQUIRED)) {
        controller->clear_streak_count = CONTROLLER_CLEAR_STREAK_REQUIRED;
    }
}

static void controller_handle_turbidity_update(controller_t *controller, int turbidity_ntu, uint32_t now_ms)
{
    if (controller == 0) {
        return;
    }

    controller->has_valid_turbidity = true;
    controller->last_turbidity_ntu = turbidity_ntu;
    controller->last_turbidity_ms = now_ms;

    if (turbidity_ntu <= CONTROLLER_CLEAR_THRESHOLD_NTU) {
        controller->clear_streak_count += 1;
        controller_clamp_clear_streak(controller);
        return;
    }

    controller->clear_streak_count = 0;
}

static bool controller_invalidate_stale_sensors(controller_t *controller, uint32_t now_ms)
{
    bool any_stale = false;

    if (controller == 0) {
        return false;
    }

    if (controller->has_valid_turbidity &&
        controller_elapsed_more_than(now_ms, controller->last_turbidity_ms, CONTROLLER_SENSOR_TIMEOUT_MS)) {
        controller->has_valid_turbidity = false;
        any_stale = true;
    }

    if (controller->has_valid_level &&
        controller_elapsed_more_than(now_ms, controller->last_level_ms, CONTROLLER_SENSOR_TIMEOUT_MS)) {
        controller->has_valid_level = false;
        any_stale = true;
    }

    if (any_stale) {
        controller->clear_streak_count = 0;
        controller->settling_started_ms = 0U;
        controller_set_safe_idle(controller);
    }

    return any_stale;
}

void controller_init(controller_t *controller)
{
    if (controller == 0) {
        return;
    }

    controller_set_safe_idle(controller);
    controller->has_valid_turbidity = false;
    controller->last_turbidity_ntu = 0;
    controller->last_turbidity_ms = 0U;
    controller->has_valid_level = false;
    controller->last_level = 0;
    controller->last_level_ms = 0U;
    controller->clear_streak_count = 0;
    controller->settling_started_ms = 0U;
}

controller_output_t controller_step(controller_t *controller, controller_input_t input)
{
    controller_output_t output = {
        .filter_on = false,
        .drain_open = false,
        .state = CONTROLLER_STATE_SAFE_IDLE,
        .state_name = controller_state_name(CONTROLLER_STATE_SAFE_IDLE),
        .changed = false,
        .timed_out = false,
    };
    bool previous_filter_on;
    bool previous_drain_open;
    controller_state_t previous_state;
    bool have_fresh_turbidity;
    bool have_fresh_level;

    if (controller == 0) {
        return output;
    }

    previous_filter_on = controller->filter_on;
    previous_drain_open = controller->drain_open;
    previous_state = controller->state;

    switch (input.kind) {
    case CONTROLLER_INPUT_TURBIDITY:
        controller_handle_turbidity_update(controller, input.turbidity_ntu, input.now_ms);
        break;
    case CONTROLLER_INPUT_LEVEL:
        controller->has_valid_level = true;
        controller->last_level = input.level;
        controller->last_level_ms = input.now_ms;
        break;
    case CONTROLLER_INPUT_SENSOR_TIMEOUT:
        controller->has_valid_turbidity = false;
        controller->has_valid_level = false;
        controller->clear_streak_count = 0;
        controller->settling_started_ms = 0U;
        controller_set_safe_idle(controller);
        output.timed_out = true;
        goto controller_step_done;
    case CONTROLLER_INPUT_INVALID_TURBIDITY:
        controller->has_valid_turbidity = false;
        controller->clear_streak_count = 0;
        controller->settling_started_ms = 0U;
        controller_set_safe_idle(controller);
        goto controller_step_done;
    case CONTROLLER_INPUT_INVALID_LEVEL:
        controller->has_valid_level = false;
        controller->clear_streak_count = 0;
        controller->settling_started_ms = 0U;
        controller_set_safe_idle(controller);
        goto controller_step_done;
    case CONTROLLER_INPUT_NONE:
    default:
        break;
    }

    if (controller_invalidate_stale_sensors(controller, input.now_ms)) {
        output.timed_out = true;
        goto controller_step_done;
    }

    have_fresh_turbidity = controller_turbidity_fresh(controller, input.now_ms);
    have_fresh_level = controller_level_fresh(controller, input.now_ms);

    if (have_fresh_level && (controller->last_level < CONTROLLER_COMPLETE_LEVEL)) {
        controller_set_complete(controller);
        goto controller_step_done;
    }

    if (!have_fresh_turbidity || !have_fresh_level) {
        controller_set_safe_idle(controller);
        goto controller_step_done;
    }

    switch (controller->state) {
    case CONTROLLER_STATE_SETTLING:
        if (controller->last_level < CONTROLLER_MIN_PROCESS_LEVEL) {
            controller_set_safe_idle(controller);
            break;
        }

        if ((input.kind == CONTROLLER_INPUT_TURBIDITY) &&
            (input.turbidity_ntu > CONTROLLER_SETTLING_RESET_THRESHOLD_NTU)) {
            controller->clear_streak_count = 0;
            controller->settling_started_ms = 0U;
            controller_set_filtering(controller);
            break;
        }

        controller_set_state(controller, CONTROLLER_STATE_SETTLING, false, false);
        if (controller_elapsed_at_least(input.now_ms, controller->settling_started_ms, CONTROLLER_SETTLING_MS) &&
            (controller->last_turbidity_ntu <= CONTROLLER_CLEAR_THRESHOLD_NTU) &&
            (controller->last_level >= CONTROLLER_MIN_PROCESS_LEVEL)) {
            controller_set_draining(controller);
        }
        break;

    case CONTROLLER_STATE_DRAINING:
        if ((input.kind == CONTROLLER_INPUT_TURBIDITY) &&
            (input.turbidity_ntu > CONTROLLER_DRAINING_DISTURBANCE_THRESHOLD_NTU) &&
            (controller->last_level >= CONTROLLER_MIN_PROCESS_LEVEL)) {
            controller->clear_streak_count = 0;
            controller->settling_started_ms = 0U;
            controller_set_filtering(controller);
            break;
        }

        controller_set_draining(controller);
        break;

    case CONTROLLER_STATE_SAFE_IDLE:
    case CONTROLLER_STATE_FILTERING:
    case CONTROLLER_STATE_COMPLETE:
    default:
        if (controller->last_level < CONTROLLER_MIN_PROCESS_LEVEL) {
            controller_set_safe_idle(controller);
            break;
        }

        if (controller->last_turbidity_ntu > CONTROLLER_CLEAR_THRESHOLD_NTU) {
            controller_set_filtering(controller);
            break;
        }

        if (controller->clear_streak_count >= CONTROLLER_CLEAR_STREAK_REQUIRED) {
            controller_set_settling(controller, input.now_ms);
            break;
        }

        controller_set_safe_idle(controller);
        break;
    }

controller_step_done:
    output.filter_on = controller->filter_on;
    output.drain_open = controller->drain_open;
    output.state = controller->state;
    output.state_name = controller_state_name(controller->state);
    output.changed =
        (previous_filter_on != controller->filter_on) ||
        (previous_drain_open != controller->drain_open) ||
        (previous_state != controller->state);
    return output;
}

const char *controller_state_name(controller_state_t state)
{
    switch (state) {
    case CONTROLLER_STATE_FILTERING:
        return "STATE FILTERING";
    case CONTROLLER_STATE_SETTLING:
        return "STATE SETTLING";
    case CONTROLLER_STATE_DRAINING:
        return "STATE DRAINING";
    case CONTROLLER_STATE_COMPLETE:
        return "STATE COMPLETE";
    case CONTROLLER_STATE_SAFE_IDLE:
    default:
        return "STATE SAFE_IDLE";
    }
}

