    bool previous_drain_open;
    controller_state_t previous_state;
    bool have_fresh_turbidity;
    bool have_fresh_level;

    if (controller == 0) {
        return output;
    }

    previous_filter_on = controller->filter_on;
    previous_drain_open = controller->drain_open;
    previous_state = controller->state;

    switch (input.kind) {
    case CONTROLLER_INPUT_TURBIDITY:
        controller_handle_turbidity_update(controller, input.turbidity_ntu, input.now_ms);
        break;
    case CONTROLLER_INPUT_LEVEL:
        controller->has_valid_level = true;
        controller->last_level = input.level;
        controller->last_level_ms = input.now_ms;
        break;
    case CONTROLLER_INPUT_SENSOR_TIMEOUT:
        controller->has_valid_turbidity = false;
        controller->has_valid_level = false;
        controller->clear_streak_count = 0;
        controller->settling_started_ms = 0U;
        controller_set_safe_idle(controller);
        output.timed_out = true;
        goto controller_step_done;
    case CONTROLLER_INPUT_INVALID_TURBIDITY:
        controller->has_valid_turbidity = false;
        controller->clear_streak_count = 0;
        controller->settling_started_ms = 0U;
        controller_set_safe_idle(controller);
        goto controller_step_done;
    case CONTROLLER_INPUT_INVALID_LEVEL:
        controller->has_valid_level = false;
        controller->clear_streak_count = 0;
        controller->settling_started_ms = 0U;
        controller_set_safe_idle(controller);
        goto controller_step_done;
    case CONTROLLER_INPUT_NONE:
    default:
        break;
    }

    if (controller_invalidate_stale_sensors(controller, input.now_ms)) {
        output.timed_out = true;
        goto controller_step_done;
    }

    have_fresh_turbidity = controller_turbidity_fresh(controller, input.now_ms);
    have_fresh_level = controller_level_fresh(controller, input.now_ms);

    if (have_fresh_level && (controller->last_level < CONTROLLER_COMPLETE_LEVEL)) {
        controller_set_complete(controller);
        goto controller_step_done;
    }

    if (!have_fresh_turbidity || !have_fresh_level) {
        controller_set_safe_idle(controller);
        goto controller_step_done;
    }

    switch (controller->state) {
    case CONTROLLER_STATE_SETTLING:
        if (controller->last_level < CONTROLLER_MIN_PROCESS_LEVEL) {
            controller_set_safe_idle(controller);
            break;
        }

        if ((input.kind == CONTROLLER_INPUT_TURBIDITY) &&
            (input.turbidity_ntu > CONTROLLER_SETTLING_RESET_THRESHOLD_NTU)) {
            controller->clear_streak_count = 0;
            controller->settling_started_ms = 0U;
